        return jsonify({"error": "malformed or empty input"}), 400

    try:
        arr = np.array(feats, dtype=float)
    except Exception:
        return jsonify({"error": "malformed or empty input"}), 400

    # Deterministic prediction derived from features.
    pred = float(arr.sum())
    return jsonify({"prediction": pred}), 200


